input.chart:
{
  "title": "Premium LTO Attachment Rates: Kiosk vs Third-Party Delivery (Top 5 Markets)",
  "transform": [
    {
      "filter": "datum.ATTACH_LOCATION_MARKET == 'New York City' || datum.ATTACH_LOCATION_MARKET == 'Long Island' || datum.ATTACH_LOCATION_MARKET == 'Los Angeles' || datum.ATTACH_LOCATION_MARKET == 'Chicago' || datum.ATTACH_LOCATION_MARKET == 'Dallas-Fort Worth'"
    },
    {
      "calculate": "datum.ATTACH_ORDER_CHANNEL == 'KIOSK' ? 'Kiosk' : '3P Delivery'",
      "as": "CHANNEL_TYPE"
    },
    {
      "aggregate": [
        {"op": "sum", "field": "SUM_LTO_TXNS", "as": "TOTAL_LTO_TXNS"},
        {"op": "sum", "field": "SUM_CHANNEL_TOTAL_TXNS", "as": "TOTAL_CHANNEL_TXNS"}
      ],
      "groupby": ["LTO_ITEM_NAME", "ATTACH_LOCATION_MARKET", "CHANNEL_TYPE"]
    },
    {
      "calculate": "100 * datum.TOTAL_LTO_TXNS / datum.TOTAL_CHANNEL_TXNS",
      "as": "ATTACH_RATE"
    }
  ],
  "mark": "bar",
  "encoding": {
    "x": {
      "field": "ATTACH_RATE",
      "type": "quantitative",
      "title": "Attachment Rate (%)"
    },
    "y": {
      "field": "ATTACH_LOCATION_MARKET",
      "type": "nominal",
      "title": "Market",
      "sort": "-x"
    },
    "yOffset": {
      "field": "LTO_ITEM_NAME",
      "type": "nominal"
    },
    "color": {
      "field": "CHANNEL_TYPE",
      "type": "nominal",
      "title": "Channel"
    }
  }
}
